class Solution:
    def minimizeXor(self, num1: int, num2: int) -> int:
        set_bits_num2 = bin(num2).count('1')
        result = num1
        for i in range(31, -1, -1):
            if (num1 >> i) & 1:
                if set_bits_num2 > 0:
                    result &= ~(1 << i)
                    set_bits_num2 -= 1
        for i in range(32):
            if (result >> i) & 1 == 0:
                if set_bits_num2 > 0:
                    result |= (1 << i)
                    set_bits_num2 -= 1
        return result
